body:
I run the command:
`iverilog -tblif ./dff_scramble.v`

The error message I get is:
`./dff_scramble.v:24: sorry: Forgot how to implement asynchronous scramble (set to x/z).
./dff_scramble.v:23: error: Unable to synthesize synchronous process.
`
It happens in synth2.cc

The file is:

``` verilog

/*
 * A D-type flip-flop to check synchronous logic works
 * correctly.
 */


module dff(
output wire [3:0] q, 
input wire [3:0] d, 
input wire clk, 
input wire rstin,
input wire ce,
input wire [3:0] oe);


reg [3:0] rg;

bufif1(q[0],rg[0],oe[0]);
bufif1(q[1],rg[1],oe[1]);
bufif1(q[2],rg[2],oe[2]);
bufif1(q[3],rg[3],oe[3]);

  always @(posedge clk or posedge rstin)
    if (rstin)
      rg <= 4'b0001;
    else
        if(ce)
        rg <= d;


endmodule // dff

```
